const input = $input.first().json;
const body = (input.body && typeof input.body === 'object') ? input.body : input;

const action = String(body.action || '').trim() || 'review_changes';
const allowed = new Set(['no_action','gather_evidence', 'review_changes', 'draft_issue', 'draft_pr', 'improve_issue', 'improve_pr']);
if (!allowed.has(action)) {
  throw new Error('Unsupported action. Use one of: no_action, gather_evidence, review_changes, draft_issue, draft_pr, improve_issue, improve_pr');
}

const owner = body.repo_owner || body.owner;
const repo = body.repo_name || body.repo;
if (!owner || !repo) throw new Error('repo_owner and repo_name are required.');

const approvePublish = body.approve_publish === true || body.approve_publish === 'true';
const confirmArtifact = body.confirm_artifact === true || body.confirm_artifact === 'true';
const githubToken = body.github_token || '';
const ollamaHost = body.ollama_host || 'http://127.0.0.1:11434';
const agentModel = body.agent_model || 'qwen2.5:7b';
const fastMode = body.fast_mode !== false && body.fast_mode !== 'false';
const maxChangedFiles = Math.max(1, Number(body.max_changed_files || (fastMode ? 8 : 15)));
const maxPatchChars = Math.max(400, Number(body.max_patch_chars || (fastMode ? 1200 : 2800)));
const baseUrl = `https://api.github.com/repos/${owner}/${repo}`;
const automationMarker = '<!-- generated-by-n8n-github-assistant -->';

const authHeader = githubToken ? (githubToken.startsWith('github_pat_') ? `Bearer ${githubToken}` : `token ${githubToken}`) : '';

async function githubGet(path) {
  const url = `${baseUrl}${path}`;
  const headers = { Accept: 'application/vnd.github+json', 'User-Agent': 'n8n-github-assistant' };
  if (authHeader) headers.Authorization = authHeader;

  try {
    return await this.helpers.httpRequest({ method: 'GET', url, headers, json: true });
  } catch (error) {
    const statusCode = error?.statusCode;
    const responseBody = error?.response?.body;

    if (statusCode === 404) {
      throw new Error(
        `GitHub returned 404 for ${url}. This usually means the repo/PR does not exist, OR the repo is private and you did not provide a token with access.`
      );
    }

    throw new Error(
      `GitHub request failed (${statusCode || 'unknown'}) for ${url}: ${error?.message || 'request failed'}
${JSON.stringify(responseBody || {}, null, 2)}`
    );
  }
}

function compactText(value, max = 12000) {
  const text = typeof value === 'string' ? value : JSON.stringify(value);
  return text.length > max ? `${text.slice(0, max)}
...<truncated>` : text;
}

const normalized = {
  action,
  owner,
  repo,
  repo_full_name: `${owner}/${repo}`,
  approve_publish: approvePublish,
  confirm_artifact: confirmArtifact,
  github_token: githubToken,
  github_token_present: Boolean(githubToken),
  ollama_host: ollamaHost,
  agent_model: agentModel,
  fast_mode: fastMode,
  max_changed_files: maxChangedFiles,
  max_patch_chars: maxPatchChars,
  user_request: body.user_request || body.prompt || '',
  metadata: body.metadata || {},
  source: body,
  agent_outputs: {},
  resolved_action: action,
  decision: null,
  loop_guard: { should_stop: false, reasons: [], marker: automationMarker, label: 'ai-generated' }
};


if (action === 'review_changes' || action === 'improve_pr') {
  const prNumber = Number(body.pr_number);
  if (!Number.isInteger(prNumber) || prNumber <= 0) throw new Error('pr_number is required for review_changes and improve_pr.');
  const pr = await githubGet(`/pulls/${prNumber}`);
  const files = await githubGet(`/pulls/${prNumber}/files?per_page=100`);
  const rankedFiles = files
    .map((file) => ({
      filename: file.filename,
      status: file.status,
      additions: file.additions,
      deletions: file.deletions,
      changes: file.changes,
      patch: compactText(file.patch || '', maxPatchChars),
    }))
    .sort((a, b) => (b.changes || 0) - (a.changes || 0));

  normalized.pr_number = prNumber;
  normalized.pull_request = {
    number: pr.number,
    title: pr.title,
    body: compactText(pr.body || '', 3000),
    state: pr.state,
    draft: Boolean(pr.draft),
    base: pr.base?.ref,
    head: pr.head?.ref,
    author: pr.user?.login || '',
    html_url: pr.html_url,
    additions: pr.additions,
    deletions: pr.deletions,
    changed_files: pr.changed_files,
  };
  normalized.diff_files = rankedFiles.slice(0, maxChangedFiles);
  normalized.diff_overview = {
    included_files: normalized.diff_files.length,
    omitted_files: Math.max(0, rankedFiles.length - normalized.diff_files.length),
    omitted_filenames: rankedFiles.slice(maxChangedFiles).map((file) => file.filename).slice(0, 20),
  };
}

if (action === 'gather_evidence') {
  // Target selection (human-provided):
  // - PR: pr_number
  // - Compare/range: base + head (or from + to)
  // - Single commit: commit (or commit_sha)
  const prNumber = body.pr_number != null ? Number(body.pr_number) : null;
  const commitSha = String(body.commit || body.commit_sha || '').trim();
  const baseRef = String(body.base || body.from || body.base_ref || '').trim();
  const headRef = String(body.head || body.to || body.head_ref || body.branch || body.ref || '').trim();

  if (prNumber && Number.isInteger(prNumber) && prNumber > 0) {
    const pr = await githubGet(`/pulls/${prNumber}`);
    const files = await githubGet(`/pulls/${prNumber}/files?per_page=100`);
    const rankedFiles = files
      .map((file) => ({
        filename: file.filename,
        status: file.status,
        additions: file.additions,
        deletions: file.deletions,
        changes: file.changes,
        patch: compactText(file.patch || '', maxPatchChars),
      }))
      .sort((a, b) => (b.changes || 0) - (a.changes || 0));

    normalized.pr_number = prNumber;
    normalized.pull_request = {
      number: pr.number,
      title: pr.title,
      body: compactText(pr.body || '', 3000),
      state: pr.state,
      draft: Boolean(pr.draft),
      base: pr.base?.ref,
      head: pr.head?.ref,
      author: pr.user?.login || '',
      html_url: pr.html_url,
      additions: pr.additions,
      deletions: pr.deletions,
      changed_files: pr.changed_files,
    };
    normalized.diff_files = rankedFiles.slice(0, maxChangedFiles);
    normalized.diff_overview = {
      included_files: normalized.diff_files.length,
      omitted_files: Math.max(0, rankedFiles.length - normalized.diff_files.length),
      omitted_filenames: rankedFiles.slice(maxChangedFiles).map((file) => file.filename).slice(0, 20),
    };
  } else if (commitSha) {
    const commit = await githubGet(`/commits/${encodeURIComponent(commitSha)}`);
    const files = Array.isArray(commit.files) ? commit.files : [];
    const rankedFiles = files
      .map((file) => ({
        filename: file.filename,
        status: file.status,
        additions: file.additions,
        deletions: file.deletions,
        changes: file.changes,
        patch: compactText(file.patch || '', maxPatchChars),
      }))
      .sort((a, b) => (b.changes || 0) - (a.changes || 0));

    normalized.commit = {
      sha: commit.sha,
      message: commit.commit?.message || '',
      author: commit.author?.login || commit.commit?.author?.name || '',
      html_url: commit.html_url,
      stats: commit.stats || {},
    };
    normalized.diff_files = rankedFiles.slice(0, maxChangedFiles);
    normalized.diff_overview = {
      included_files: normalized.diff_files.length,
      omitted_files: Math.max(0, rankedFiles.length - normalized.diff_files.length),
      omitted_filenames: rankedFiles.slice(maxChangedFiles).map((file) => file.filename).slice(0, 20),
    };
  } else {
    // Compare / range / branch. If nothing is provided, default to the repo default branch (usually main).
    const repoInfo = await githubGet('');
    const defaultBranch = repoInfo.default_branch || 'main';
    const head = headRef || defaultBranch;
    const base = baseRef || `${head}~1`;

    let compare = null;
    try {
      compare = await githubGet(`/compare/${encodeURIComponent(base)}...${encodeURIComponent(head)}`);
    } catch (e) {
      // Fallback: if compare fails (e.g. repo has only 1 commit), analyze the single commit at head.
      const commit = await githubGet(`/commits/${encodeURIComponent(head)}`);
      const files = Array.isArray(commit.files) ? commit.files : [];
      const rankedFiles = files
        .map((file) => ({
          filename: file.filename,
          status: file.status,
          additions: file.additions,
          deletions: file.deletions,
          changes: file.changes,
          patch: compactText(file.patch || '', maxPatchChars),
        }))
        .sort((a, b) => (b.changes || 0) - (a.changes || 0));

      normalized.compare = {
        base,
        head,
        html_url: '',
        status: 'fallback_single_commit',
        ahead_by: 0,
        behind_by: 0,
        total_commits: 1,
        merge_base_sha: '',
        commits_sample: [{ sha: commit.sha, message: commit.commit?.message || '' }],
      };

      normalized.commit = {
        sha: commit.sha,
        message: commit.commit?.message || '',
        author: commit.author?.login || commit.commit?.author?.name || '',
        html_url: commit.html_url,
        stats: commit.stats || {},
      };

      normalized.diff_files = rankedFiles.slice(0, maxChangedFiles);
      normalized.diff_overview = {
        included_files: normalized.diff_files.length,
        omitted_files: Math.max(0, rankedFiles.length - normalized.diff_files.length),
        omitted_filenames: rankedFiles.slice(maxChangedFiles).map((file) => file.filename).slice(0, 20),
      };
    }

    if (compare) {
      const files = Array.isArray(compare.files) ? compare.files : [];
      const rankedFiles = files
        .map((file) => ({
          filename: file.filename,
          status: file.status,
          additions: file.additions,
          deletions: file.deletions,
          changes: file.changes,
          patch: compactText(file.patch || '', maxPatchChars),
        }))
        .sort((a, b) => (b.changes || 0) - (a.changes || 0));

      normalized.compare = {
        base,
        head,
        html_url: compare.html_url || '',
        status: compare.status || '',
        ahead_by: compare.ahead_by,
        behind_by: compare.behind_by,
        total_commits: compare.total_commits,
        merge_base_sha: compare.merge_base_commit?.sha || '',
        commits_sample: Array.isArray(compare.commits)
          ? compare.commits.slice(0, 20).map((c) => ({ sha: c.sha, message: c.commit?.message || '' }))
          : [],
      };

      normalized.diff_files = rankedFiles.slice(0, maxChangedFiles);
      normalized.diff_overview = {
        included_files: normalized.diff_files.length,
        omitted_files: Math.max(0, rankedFiles.length - normalized.diff_files.length),
        omitted_filenames: rankedFiles.slice(maxChangedFiles).map((file) => file.filename).slice(0, 20),
      };
    }
  }
}


if (action === 'improve_issue') {
  const issueNumber = Number(body.issue_number);
  if (!Number.isInteger(issueNumber) || issueNumber <= 0) throw new Error('issue_number is required for improve_issue.');
  const issue = await githubGet(`/issues/${issueNumber}`);
  normalized.issue_number = issueNumber;
  normalized.issue = { number: issue.number, title: issue.title, body: compactText(issue.body || '', 5000), state: issue.state, labels: (issue.labels || []).map((label) => typeof label === 'string' ? label : label.name), assignees: (issue.assignees || []).map((user) => user.login), html_url: issue.html_url };
}

if (action === 'draft_issue') {
  normalized.issue_seed = { title: body.title || '', problem_statement: compactText(body.problem_statement || body.summary || '', 3000), context: compactText(body.context || '', 4000), acceptance_criteria: body.acceptance_criteria || [], labels: body.labels || [], assignees: body.assignees || [] };
}

if (action === 'draft_pr') {
  normalized.pull_request_seed = { title: body.title || '', summary: compactText(body.summary || body.problem_statement || '', 3000), context: compactText(body.context || '', 4000), acceptance_criteria: body.acceptance_criteria || [], labels: body.labels || [], reviewers: body.reviewers || [], base: body.base || 'main', head: body.head || '', linked_issues: body.linked_issues || [] };
}

return [{ json: normalized }];

const input = $input.first().json;
const fastMode = input.fast_mode !== false;

// For gather_evidence, avoid slow local inference. Build a deterministic evidence summary.
if (input.action === 'gather_evidence') {
  const files = Array.isArray(input.diff_files) ? input.diff_files : [];
  const totalChanges = files.reduce((sum, f) => sum + (Number(f.changes) || 0), 0);
  const totalAdditions = files.reduce((sum, f) => sum + (Number(f.additions) || 0), 0);
  const totalDeletions = files.reduce((sum, f) => sum + (Number(f.deletions) || 0), 0);

  const filenames = files.map((f) => String(f.filename || '')).filter(Boolean);
  const topPaths = filenames.slice(0, 12);

  const touchedTests = filenames.some((f) => /(^|\/)(__tests__|test|tests)\//i.test(f) || /(\.test\.|\.spec\.)/i.test(f));
  const touchedMigrations = filenames.some((f) => /(migrations|schema|db|\.sql)/i.test(f));
  const touchedAuth = filenames.some((f) => /(auth|oauth|jwt|session|crypto|security)/i.test(f));
  const touchedDeps = filenames.some((f) => /(package\.json|package-lock\.json|pnpm-lock\.yaml|yarn\.lock|requirements\.txt|poetry\.lock|Pipfile\.lock)/i.test(f));

  let risk = 'low';
  if (totalChanges > 600 || touchedDeps) risk = 'medium';
  if (totalChanges > 1500 || touchedMigrations || touchedAuth) risk = 'high';

  const target = input.pull_request
    ? `PR #${input.pull_request.number}: ${input.pull_request.title}`
    : input.commit
      ? `Commit ${input.commit.sha.slice(0, 8)}: ${(input.commit.message || '').split(/\r?\n/)[0]}`
      : input.compare
        ? `Compare ${input.compare.base}...${input.compare.head}`
        : 'Repository changes';

  const behavior = [
    `Target: ${target}`,
    `Files touched (top): ${topPaths.join(', ') || 'none'}`,
    `Net change: +${totalAdditions} / -${totalDeletions} across ${filenames.length} files`,
    touchedTests ? 'Tests appear to be touched.' : 'No obvious test files detected in the change list.',
    touchedMigrations ? 'DB/schema/migration files detected.' : null,
    touchedAuth ? 'Auth/security-adjacent files detected.' : null,
    touchedDeps ? 'Dependency/lockfile changes detected.' : null,
  ].filter(Boolean).join('\n');

  const analyzer = {
    objective: (input.user_request || '').trim() || 'Summarize evidence for a human decision.',
    files_affected: topPaths,
    behavior_change: behavior,
    risk_level: risk,
    key_points: [],
    missing_information: [],
  };

  return [{ json: { ...input, agent_outputs: { ...input.agent_outputs, analyzer } } }];
}

// Non-evidence actions still use the model.
const ollamaUrl = `${input.ollama_host.replace(/\/$/, '')}/api/chat`;
function parseJson(text) { if (!text) return {}; try { return JSON.parse(text); } catch (e) {} const m = text.match(/```(?:json)?\s*([\s\S]*?)```/i); if (m) { try { return JSON.parse(m[1].trim()); } catch (e) {} } return {}; }
const context = JSON.stringify({ action: input.action, repository: input.repo_full_name, user_request: input.user_request, verifier: input.agent_outputs?.verifier, issue_seed: input.issue_seed, pull_request_seed: input.pull_request_seed, issue: input.issue, pull_request: input.pull_request, diff_files: input.diff_files, diff_overview: input.diff_overview, metadata: input.metadata, fast_mode: fastMode });
const data = await this.helpers.httpRequest({ method: 'POST', url: ollamaUrl, headers: { 'Content-Type': 'application/json' }, body: { model: input.agent_model, messages: [{ role: 'system', content: 'You are the Repository Analyst. Use the verifier output first, then summarize the code change evidence for a human decision. Return JSON only with keys: objective, files_affected, behavior_change, risk_level, key_points, missing_information. risk_level must be one of low, medium, high.' }, { role: 'user', content: context }], stream: false, format: 'json', options: { temperature: 0.1, num_predict: fastMode ? 500 : 800, num_ctx: fastMode ? 8192 : 16384 } }, json: true });
const analyzer = parseJson(data.message?.content || '{}');
return [{ json: { ...input, agent_outputs: { ...input.agent_outputs, analyzer } } }];

const input = $input.first().json;
const fastMode = input.fast_mode !== false;
const ollamaUrl = `${input.ollama_host.replace(/\/$/, '')}/api/chat`;
const loopGuard = input.loop_guard || { should_stop: false, reasons: [], marker: '<!-- generated-by-n8n-github-assistant -->' };

function parseJson(text) {
  if (!text) return {};
  try { return JSON.parse(text); } catch (e) {}
  const m = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (m) {
    try { return JSON.parse(m[1].trim()); } catch (e) {}
  }
  return {};
}
function maybeLogin(value) { return typeof value === 'string' ? value.trim().toLowerCase() : ''; }
function hasAutomationMarker(value) { return typeof value === 'string' && value.includes(loopGuard.marker); }

const reasons = [];
const senderLogin = maybeLogin(input.source?.sender?.login || input.source?.sender_login);
const issueAuthor = maybeLogin(input.issue?.author || input.source?.issue?.user?.login);
const prAuthor = maybeLogin(input.pull_request?.author || input.source?.pull_request?.user?.login);

if (senderLogin && (senderLogin.includes('[bot]') || senderLogin.includes('n8n'))) reasons.push(`sender ${senderLogin} is an automation account`);
if (issueAuthor && (issueAuthor.includes('[bot]') || issueAuthor.includes('n8n'))) reasons.push(`issue author ${issueAuthor} is an automation account`);
if (prAuthor && (prAuthor.includes('[bot]') || prAuthor.includes('n8n'))) reasons.push(`pull request author ${prAuthor} is an automation account`);
if (hasAutomationMarker(input.issue?.body) || hasAutomationMarker(input.pull_request?.body) || hasAutomationMarker(input.source?.issue?.body) || hasAutomationMarker(input.source?.pull_request?.body)) reasons.push('artifact already contains the automation marker');

if (reasons.length > 0) {
  const verifier = { verification_status: 'blocked', verified_facts: [], assumptions: [], missing_information: [], blockers: reasons, next_step: `Loop guard stopped this run: ${reasons.join('; ')}.` };
  return [{ json: { ...input, loop_guard: { ...loopGuard, should_stop: true, reasons }, agent_outputs: { ...input.agent_outputs, verifier } } }];
}

// Evidence-only runs should be fast and not blocked by slow local inference.
if (input.action === 'gather_evidence' && !input.approve_publish) {
  const verifier = {
    verification_status: 'pass',
    verified_facts: ['Loop guard passed. Evidence run only.'],
    assumptions: [],
    missing_information: [],
    blockers: [],
    next_step: "Review the evidence output and choose action 'draft_issue' or 'draft_pr'.",
  };
  return [{ json: { ...input, agent_outputs: { ...input.agent_outputs, verifier } } }];
}

const filesAffected = Array.isArray(input.diff_files)
  ? input.diff_files.map((f) => ({ filename: f.filename, status: f.status, changes: f.changes, additions: f.additions, deletions: f.deletions }))
  : [];

const context = JSON.stringify({
  action: input.action,
  repository: input.repo_full_name,
  user_request: input.user_request,
  target: {
    pr_number: input.pr_number || null,
    commit: input.commit?.sha || null,
    compare: input.compare ? { base: input.compare.base, head: input.compare.head, total_commits: input.compare.total_commits } : null,
  },
  issue: input.issue ? { number: input.issue.number, title: input.issue.title, state: input.issue.state } : null,
  pull_request: input.pull_request ? { number: input.pull_request.number, title: input.pull_request.title, state: input.pull_request.state, draft: input.pull_request.draft, base: input.pull_request.base, head: input.pull_request.head, url: input.pull_request.html_url } : null,
  files_affected: filesAffected,
  diff_overview: input.diff_overview || null,
  metadata: input.metadata,
});

const model = input.verifier_model || input.agent_model;
const data = await this.helpers.httpRequest({
  method: 'POST',
  url: ollamaUrl,
  headers: { 'Content-Type': 'application/json' },
  body: {
    model,
    messages: [
      { role: 'system', content: 'You are the Verifier Assistant. Verify whether the request has enough grounded context to proceed safely. Return JSON only with keys: verification_status, verified_facts, assumptions, missing_information, blockers, next_step. verification_status must be one of pass, caution, blocked.' },
      { role: 'user', content: context },
    ],
    stream: false,
    format: 'json',
    options: {
      temperature: 0.1,
      num_predict: fastMode ? 220 : 350,
      num_ctx: fastMode ? 4096 : 8192,
    },
  },
  json: true,
});

const verifier = parseJson(data.message?.content || '{}');
return [{ json: { ...input, agent_outputs: { ...input.agent_outputs, verifier } } }];

const input = $input.first().json;
const fastMode = input.fast_mode !== false;

// For gather_evidence, avoid slow local inference. Provide a lightweight review summary.
if (input.action === 'gather_evidence') {
  const analyzer = input.agent_outputs?.analyzer || {};
  const risk = analyzer.risk_level || '';

  const reviewer = {
    review_summary: 'Evidence gathered. No automated deep review performed in evidence mode.',
    risk_level: risk,
    blocking_concerns: [],
    non_blocking_concerns: [],
    suggested_checks: [
      'Confirm behavior changes against requirements.',
      'Run unit/integration tests for touched areas.',
      'Check for missing docs/rollout notes if behavior changes are user-visible.',
    ],
    tone_guidance: 'Use neutral, factual language when drafting the issue/PR.',
  };

  return [{ json: { ...input, agent_outputs: { ...input.agent_outputs, reviewer } } }];
}

const ollamaUrl = `${input.ollama_host.replace(/\/$/, '')}/api/chat`;
function parseJson(text) { if (!text) return {}; try { return JSON.parse(text); } catch (e) {} const m = text.match(/```(?:json)?\s*([\s\S]*?)```/i); if (m) { try { return JSON.parse(m[1].trim()); } catch (e) {} } return {}; }
const context = JSON.stringify({ action: input.action, repository: input.repo_full_name, user_request: input.user_request, issue_seed: input.issue_seed, pull_request_seed: input.pull_request_seed, issue: input.issue, pull_request: input.pull_request, diff_files: input.diff_files, diff_overview: input.diff_overview, metadata: input.metadata, analyzer: input.agent_outputs?.analyzer, fast_mode: fastMode });
const data = await this.helpers.httpRequest({ method: 'POST', url: ollamaUrl, headers: { 'Content-Type': 'application/json' }, body: { model: input.agent_model, messages: [{ role: 'system', content: 'You are the GitHub Review Agent. Challenge the analyst framing. Return JSON only with keys: review_summary, risk_level, blocking_concerns, non_blocking_concerns, suggested_checks, tone_guidance. risk_level must be one of low, medium, high.' }, { role: 'user', content: context }], stream: false, format: 'json', options: { temperature: 0.1, num_predict: fastMode ? 500 : 800, num_ctx: fastMode ? 8192 : 16384 } }, json: true });
const reviewer = parseJson(data.message?.content || '{}');
return [{ json: { ...input, agent_outputs: { ...input.agent_outputs, reviewer } } }];

const input = $input.first().json;

// Human choice only: issue vs PR must be selected explicitly.
const allowed = new Set(['gather_evidence', 'review_changes', 'draft_issue', 'draft_pr', 'improve_issue', 'improve_pr']);
if (!allowed.has(input.action)) {
  throw new Error("Choose an artifact type explicitly. Use action 'draft_issue' or 'draft_pr' (or improve_issue / improve_pr / review_changes)." );
}

let recommendation = 'no_action';
if (input.action === 'draft_issue' || input.action === 'improve_issue') recommendation = 'issue';
if (input.action === 'draft_pr' || input.action === 'improve_pr') recommendation = 'pull_request';

return [{
  json: {
    ...input,
    decision: {
      recommendation,
      rationale: 'Artifact type selected explicitly via action.',
      confidence: 'high',
      next_action: input.action,
    },
    resolved_action: input.action,
  }
}];

const input = $input.first().json;
const fastMode = input.fast_mode !== false;
const ollamaUrl = `${input.ollama_host.replace(/\/$/, '')}/api/chat`;
const marker = input.loop_guard?.marker || '<!-- generated-by-n8n-github-assistant -->';
